        public SamlConditions getConditions() { return conditions; }
        public void setConditions(SamlConditions conditions) { this.conditions = conditions; }
        public AuthnStatement getAuthnStatement() { return authnStatement; }
        public void setAuthnStatement(AuthnStatement authnStatement) { this.authnStatement = authnStatement; }
        public Map<String, List<String>> getAttributes() { return attributes; }
        public void setAttributes(Map<String, List<String>> attributes) { this.attributes = attributes; }

        public String getAttributeValue(String name) {
            List<String> values = attributes != null ? attributes.get(name) : null;
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "SamlAssertion{id='" + assertionId + "', issuer='" + issuer +
                    "', subject=" + subject + ", attributes=" + (attributes != null ? attributes.keySet() : "none") + "}";
        }
